// Validate secret and extract fields
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
const brand_id   = body.brand_id   || '';
const title      = body.title      || '';
const format     = body.format     || 'reel';
const brief      = body.brief      || {};

if (!content_id) throw new Error('Missing required field: content_id');
if (!brief.objective) throw new Error('Missing required field: brief.objective');

return [{ json: { content_id, brand_id, title, format, brief } }];

// Step 1: Enhance Brief via LiteLLM (eco model — non-creative metadata)
const validate = $('Validate Secret').first().json;
const profile  = $input.first().json;
const content  = profile.body || profile;
const brand_tone = content.brand_tone || content.tone || 'professionnel et direct';

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'deepseek-v3',
      messages: [
        {
          role: 'system',
          content: `You are a content strategist for Instagram. Enhance this brief with specific KPIs, audience insights, and hook angles. Brand tone: ${brand_tone}. Respond in JSON with fields: kpis (array), audience_insights (string), hook_angles (array of 3), enhanced_objective (string).`
        },
        {
          role: 'user',
          content: JSON.stringify(validate.brief)
        }
      ],
      max_tokens: 1500,
      temperature: 0.7
    }
  });
  const text = response.choices?.[0]?.message?.content || '{}';
  try { result = JSON.parse(text); } catch { result = { raw: text }; }
} catch (e) {
  result = { error: e.message };
}

return [{ json: { ...validate, brand_tone, step1_enhanced_brief: result } }];

// Step 2: Research — trending topics and competitor insights (eco model)
const data = $input.first().json;

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'deepseek-v3',
      messages: [
        {
          role: 'system',
          content: 'Research trending topics and competitor content related to this brief. Output structured insights as JSON with fields: trending_topics (array), competitor_angles (array), best_posting_times (string), content_gaps (array), recommended_hashtags (array of 10).'
        },
        {
          role: 'user',
          content: `Brief: ${JSON.stringify(data.brief)}\nEnhanced: ${JSON.stringify(data.step1_enhanced_brief)}`
        }
      ],
      max_tokens: 2000,
      temperature: 0.5
    }
  });
  const text = response.choices?.[0]?.message?.content || '{}';
  try { result = JSON.parse(text); } catch { result = { raw: text }; }
} catch (e) {
  result = { error: e.message };
}

return [{ json: { ...data, step2_research: result } }];

// Step 3: Moodboard Prompts — 4-6 image prompts (eco model)
const data = $input.first().json;

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'deepseek-v3',
      messages: [
        {
          role: 'system',
          content: 'Generate 4-6 detailed image generation prompts for a moodboard based on the content brief and research insights. Output as a JSON array of strings. Each prompt should be 1-2 sentences, highly descriptive, suitable for Stable Diffusion or Seedream image generation.'
        },
        {
          role: 'user',
          content: `Brief: ${JSON.stringify(data.brief)}\nResearch: ${JSON.stringify(data.step2_research)}\nBrand tone: ${data.brand_tone}`
        }
      ],
      max_tokens: 1500,
      temperature: 0.7
    }
  });
  const text = response.choices?.[0]?.message?.content || '[]';
  try { result = JSON.parse(text); } catch { result = [text]; }
  if (!Array.isArray(result)) result = [String(result)];
} catch (e) {
  result = [{ error: e.message }];
}

return [{ json: { ...data, step3_moodboard_prompts: result } }];

// Step 4: Concept & Hook — main creative step (premium model)
const data = $input.first().json;

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'gpt-4o-mini',
      messages: [
        {
          role: 'system',
          content: `You are a viral content creator specializing in Instagram Reels. Brand tone: ${data.brand_tone}. Write a full concept document as JSON with fields: hook (first 3 seconds script, max 15 words), narrative_arc (string), visual_style (string), cta (call-to-action text), emotional_trigger (string), virality_score (1-10 with reasoning).`
        },
        {
          role: 'user',
          content: `Title: ${data.title}\nFormat: ${data.format}\nBrief: ${JSON.stringify(data.brief)}\nResearch insights: ${JSON.stringify(data.step2_research)}\nHook angles: ${JSON.stringify(data.step1_enhanced_brief?.hook_angles || [])}`
        }
      ],
      max_tokens: 2000,
      temperature: 0.8
    }
  });
  const text = response.choices?.[0]?.message?.content || '{}';
  try { result = JSON.parse(text); } catch { result = { raw: text }; }
} catch (e) {
  result = { error: e.message };
}

return [{ json: { ...data, step4_concept: result } }];

// Step 5: Casting — characters and personas needed (eco model)
const data = $input.first().json;

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'deepseek-v3',
      messages: [
        {
          role: 'system',
          content: 'Based on the concept, define the casting for this content. Output as JSON with fields: characters (array of objects with name, role, visual_description, voice_type), presenter_style (string), on_screen_text_needed (boolean), special_requirements (array).'
        },
        {
          role: 'user',
          content: `Concept: ${JSON.stringify(data.step4_concept)}\nHook: ${data.step4_concept?.hook || ''}\nVisual style: ${data.step4_concept?.visual_style || ''}`
        }
      ],
      max_tokens: 1000,
      temperature: 0.5
    }
  });
  const text = response.choices?.[0]?.message?.content || '{}';
  try { result = JSON.parse(text); } catch { result = { raw: text }; }
} catch (e) {
  result = { error: e.message };
}

return [{ json: { ...data, step5_casting: result } }];

// Store all step results in NocoDB via cf-update-content
const data = $input.first().json;

try {
  await $http.request({
    method: 'POST',
    url: 'http://localhost:5678/webhook/cf-update-content',
    headers: { 'Content-Type': 'application/json' },
    body: {
      secret: $env.N8N_WEBHOOK_HMAC_SECRET,
      action: 'update_content',
      content_id: data.content_id,
      fields: {
        current_step: 5,
        status: 'awaiting_validation',
        step1_enhanced_brief: JSON.stringify(data.step1_enhanced_brief),
        step2_research: JSON.stringify(data.step2_research),
        step3_moodboard_prompts: JSON.stringify(data.step3_moodboard_prompts),
        step4_concept: JSON.stringify(data.step4_concept),
        step5_casting: JSON.stringify(data.step5_casting)
      }
    }
  });
} catch (e) {
  // Log but do not fail — content already generated
  console.error('cf-update-content failed:', e.message);
}

return [{ json: data }];

// Sync calendar — create Plane work item for new content (first execution only)
const data = $('Store Results').first().json;

try {
  // Only call on first execution (step was 0 or undefined before)
  await $http.request({
    method: 'POST',
    url: 'http://localhost:5678/webhook/cf-calendar-sync',
    headers: { 'Content-Type': 'application/json' },
    body: {
      secret: $env.N8N_WEBHOOK_HMAC_SECRET,
      action: 'sync_content',
      content_id: data.content_id,
      title: data.title,
      format: data.format
    }
  });
} catch (e) {
  // Calendar sync is non-blocking
  console.error('cf-calendar-sync failed:', e.message);
}

const concept_summary = data.step4_concept?.hook || data.step4_concept?.raw?.substring(0, 100) || 'Concept generated';
return [{ json: { content_id: data.content_id, concept_summary, steps_completed: [1, 2, 3, 4, 5] } }];
